import { useEffect, useRef, useState } from "react";
import { Link } from "react-router-dom";

export default function Navbar() {
  const [open, setOpen] = useState(false);
  const navbarRef = useRef(null);

  const closeMenu = () => setOpen(false);

  useEffect(() => {
    const handleOutsideClick = (event) => {
      if (navbarRef.current && !navbarRef.current.contains(event.target)) {
        closeMenu();
      }
    };

    const handleEscapeKey = (event) => {
      if (event.key === "Escape") {
        closeMenu();
      }
    };

    const handleScroll = () => {
      closeMenu();
    };

    document.addEventListener("mousedown", handleOutsideClick);
    document.addEventListener("touchstart", handleOutsideClick);
    document.addEventListener("keydown", handleEscapeKey);
    window.addEventListener("scroll", handleScroll, { passive: true });

    return () => {
      document.removeEventListener("mousedown", handleOutsideClick);
      document.removeEventListener("touchstart", handleOutsideClick);
      document.removeEventListener("keydown", handleEscapeKey);
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  return (
    <nav className="navbar navbar-menu-shell" aria-label="Primary" ref={navbarRef}>
      <button
        type="button"
        className="navbar-toggle"
        aria-label="Open menu"
        aria-expanded={open}
        onClick={() => setOpen((value) => !value)}
      >
        <span className="navbar-toggle-line" />
        <span className="navbar-toggle-line" />
        <span className="navbar-toggle-line" />
      </button>

      {open && (
        <div className="navbar-menu" role="menu">
          <div className="navbar-menu-header">
            <span>New customer?</span>
            <Link to="/signup" onClick={closeMenu} className="navbar-menu-signup">
              Sign Up
            </Link>
          </div>

          <div className="navbar-menu-list">
            <Link to="/profile" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">👤</span>
              <span>My Profile</span>
            </Link>
            <Link to="/orders" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">✦</span>
              <span>Orders</span>
            </Link>
            <Link to="/shop-register" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">🏪</span>
              <span>Become a Seller</span>
            </Link>
            <Link to="/cart" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">♡</span>
              <span>Wishlist</span>
            </Link>
            <Link to="/my-medicines" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">🎁</span>
              <span>Rewards</span>
            </Link>
            <Link to="/cart" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">🎁</span>
              <span>Gift Cards</span>
            </Link>
            <Link to="/profile" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">🔔</span>
              <span>Notification Preferences</span>
            </Link>
            <Link to="/orders" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">🎧</span>
              <span>24x7 Customer Care</span>
            </Link>
            <Link to="/shop-register" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">📢</span>
              <span>Advertise</span>
            </Link>
            <Link to="/" onClick={closeMenu} className="navbar-menu-item" role="menuitem">
              <span className="navbar-menu-icon">⬇</span>
              <span>Download App</span>
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
}
